<?php require_once APP_ROOT.'/lib/mod_cron.php';$available=cron_available();$jobs=$available?cron_list():[];$runs=cron_runs();$whoami=trim(shell_exec('whoami 2>/dev/null')?:'web user');$scheduled=array_values(array_filter($jobs,fn($j)=>($j['type']??'')==='job')); ?>
<div class="page-header"><div><h1 class="page-title">Cron Jobs</h1><p class="page-subtitle"><?= count($scheduled) ?> scheduled tasks · running as <span class="mono"><?= e($whoami) ?></span></p></div><?php if($available): ?><div class="page-actions"><button class="btn btn-primary" id="cronNew"><i data-lucide="plus"></i>New Cron Job</button></div><?php endif; ?></div>
<?php if(!$available): ?><div class="card"><div class="empty-state"><div class="es-icon"><i data-lucide="clock"></i></div><div>crontab is not available.</div></div></div><?php else: ?>
<div class="card" style="margin-bottom:16px"><div class="card-header"><h3>Scheduled jobs</h3><span class="muted"><?= count($scheduled) ?> jobs</span></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Schedule</th><th>Command</th><th>User</th><th>Status</th><th style="text-align:right">Actions</th></tr></thead><tbody>
<?php foreach($scheduled as $job): ?><tr><td><div class="mono" style="font-weight:600;color:var(--blue-400)"><?= e($job['schedule']) ?></div></td><td class="mono" style="word-break:break-all"><?= e($job['command']) ?></td><td class="mono text-tertiary"><?= e($whoami) ?></td><td><span class="badge badge-emerald"><span class="bdot"></span>Enabled</span></td><td style="text-align:right"><div class="flex gap-1" style="justify-content:flex-end"><button class="icon-btn" data-cron-run="<?= (int)$job['index'] ?>" title="Run now"><i data-lucide="play"></i></button><button class="icon-btn" data-cron-edit="<?= (int)$job['index'] ?>" data-schedule="<?= e($job['schedule']) ?>" data-command="<?= e($job['command']) ?>" title="Edit"><i data-lucide="pencil"></i></button><button class="icon-btn" data-cron-del="<?= (int)$job['index'] ?>" title="Delete" style="color:var(--red-400)"><i data-lucide="trash-2"></i></button></div></td></tr><?php endforeach; ?>
<?php if(!$scheduled): ?><tr><td colspan="5" class="text-tertiary" style="text-align:center;padding:28px">No cron jobs yet.</td></tr><?php endif; ?>
</tbody></table></div></div>
<div class="card"><div class="card-header"><h3>Recent runs</h3><span class="muted">Manual executions from Nebula</span></div><div class="table-wrap"><table class="data-table"><thead><tr><th>Time</th><th>Command</th><th>Exit</th><th>Output</th></tr></thead><tbody><?php foreach($runs as $run): ?><tr><td class="mono text-tertiary"><?= e(date('M j, H:i',strtotime($run['time']??'now'))) ?></td><td class="mono"><?= e($run['command']??'') ?></td><td><span class="badge <?= ($run['exit']??1)===0?'badge-emerald':'badge-red' ?>"><?= (int)($run['exit']??1) ?></span></td><td class="mono text-tertiary" style="max-width:420px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis"><?= e(trim($run['output']??'')?:'–') ?></td></tr><?php endforeach; ?><?php if(!$runs): ?><tr><td colspan="4" class="text-tertiary" style="text-align:center;padding:24px">No manual runs yet.</td></tr><?php endif; ?></tbody></table></div></div>
<div class="drawer-overlay hidden" id="cronDrawer"><div class="drawer"><div class="drawer-header"><div><strong id="cronDrawerTitle">New Cron Job</strong><div class="muted" style="font-size:11px">Configure a standard five-part schedule or @keyword</div></div><button class="icon-btn" data-close-cron><i data-lucide="x"></i></button></div><div class="drawer-body"><input type="hidden" id="cronIndex"><div style="margin-bottom:18px"><label class="field-label">Quick presets</label><div class="flex gap-2" style="flex-wrap:wrap"><?php foreach(['@hourly','@daily','@weekly','@monthly','@reboot','*/5 * * * *'] as $preset): ?><button class="chip" data-cron-preset="<?= e($preset) ?>" type="button"><?= e($preset) ?></button><?php endforeach; ?></div></div><div style="margin-bottom:18px"><label class="field-label">Schedule</label><input class="input mono" id="cronSchedule" value="0 2 * * *"></div><div><label class="field-label">Command</label><textarea class="input mono" id="cronCommand" rows="6" placeholder="/usr/bin/php /var/www/site/artisan schedule:run"></textarea></div></div><div class="drawer-footer"><button class="btn btn-secondary" data-close-cron>Cancel</button><button class="btn btn-primary" id="cronSave"><i data-lucide="save"></i>Save job</button></div></div></div>
<script>document.addEventListener('DOMContentLoaded',()=>{const{apiPost,toast}=window.Nebula,drawer=document.getElementById('cronDrawer'),idx=document.getElementById('cronIndex'),schedule=document.getElementById('cronSchedule'),command=document.getElementById('cronCommand');const open=(job=null)=>{idx.value=job?.index??'';schedule.value=job?.schedule||'0 2 * * *';command.value=job?.command||'';document.getElementById('cronDrawerTitle').textContent=job?'Edit Cron Job':'New Cron Job';drawer.classList.remove('hidden');};document.getElementById('cronNew').onclick=()=>open();document.querySelectorAll('[data-close-cron]').forEach(b=>b.onclick=()=>drawer.classList.add('hidden'));document.querySelectorAll('[data-cron-preset]').forEach(b=>b.onclick=()=>schedule.value=b.dataset.cronPreset);document.querySelectorAll('[data-cron-edit]').forEach(b=>b.onclick=()=>open({index:+b.dataset.cronEdit,schedule:b.dataset.schedule,command:b.dataset.command}));document.getElementById('cronSave').onclick=async()=>{const r=await apiPost('cron',{action:idx.value?'update':'add',index:+idx.value,schedule:schedule.value,command:command.value});toast(r.ok?'Cron job saved':(r.error||'Save failed'),r.ok?'success':'error');if(r.ok)setTimeout(()=>location.reload(),350);};document.querySelectorAll('[data-cron-del]').forEach(b=>b.onclick=async()=>{if(!confirm('Delete this cron job?'))return;const r=await apiPost('cron',{action:'delete',index:+b.dataset.cronDel});toast(r.ok?'Cron job deleted':(r.error||'Delete failed'),r.ok?'success':'error');if(r.ok)setTimeout(()=>location.reload(),300);});document.querySelectorAll('[data-cron-run]').forEach(b=>b.onclick=async()=>{b.disabled=true;const r=await apiPost('cron',{action:'run',index:+b.dataset.cronRun});b.disabled=false;toast(r.ok?'Cron command completed':(r.error||'Command failed'),r.ok?'success':'error');setTimeout(()=>location.reload(),500);});});</script>
<?php endif; ?>
